const updateSpeciesNamesForGenus = `-- name: UpdateSpeciesNamesForGenus :exec
UPDATE species
SET name = REPLACE(name, SUBSTR(name, 1, INSTR(name, ' ') - 1), ?1)
WHERE id IN (
    SELECT st.species_id
    FROM taxonomy AS t
    INNER JOIN speciestaxonomy AS st ON t.id = st.taxonomy_id
    WHERE t.id = ?2
)
`

type UpdateSpeciesNamesForGenusParams struct {
	NewGenus   string `json:"new_genus"`
	TaxonomyID int64  `json:"taxonomy_id"`
}

// Update species names when genus name changes (replace genus part of binomial)
// @new_genus: the new genus name to use
// @taxonomy_id: the taxonomy ID of the genus
func (q *Queries) UpdateSpeciesNamesForGenus(ctx context.Context, arg UpdateSpeciesNamesForGenusParams) error {
	_, err := q.db.ExecContext(ctx, updateSpeciesNamesForGenus, arg.NewGenus, arg.TaxonomyID)
	return err
}

